import { Button, Container, Dialog, DialogActions, DialogContent, DialogContentText, Grid, makeStyles, useMediaQuery, useTheme } from '@material-ui/core'
import React from 'react'

const useStyle = makeStyles(theme => {
    return {

    }
})



export default function CreateClassroom() {
    const theme = useTheme ();
    const fullScreen = useMediaQuery(theme.breakpoints.down('sm'));



  return (
    <>
        <Container>
            <Grid>
            <Dialog
                            fullScreen={fullScreen}
                            open= 'true'
                        >
                            <DialogContent>
                                <DialogContentText>
                                    Are you sure you want to post this?
                                </DialogContentText>
                            </DialogContent>
                            <DialogActions>
                                <Button autoFocus color="primary">
                                    Cancel
                                </Button>
                                <Button  color="primary" autoFocus>
                                    Confirm
                                </Button>
                            </DialogActions>
                        </Dialog>
            </Grid>
        </Container>
    </>
  )
}
